  "inlineSchema": "generator client {\n  provider      = \"prisma-client-js\"\n  binaryTargets = [\"native\", \"debian-openssl-3.0.x\"]\n}\n\ndatasource db {\n  provider  = \"postgresql\"\n  url       = env(\"DATABASE_URL\")\n  directUrl = env(\"DIRECT_URL\")\n}\n\nmodel User {\n  id        String   @id @default(cuid())\n  userType  String // 'instructor' or 'aprendiz'\n  fullName  String\n  document  String   @unique\n  email     String   @unique\n  password  String\n  avatarUrl String?\n  nfcUid    String?  @unique\n  huellas   Int[]    @default([])\n  createdAt DateTime @default(now())\n\n  // Relations\n  fichasAdmin   Ficha[]              @relation(\"InstructorAdmin\")\n  fichasInst    FichaInstructor[]\n  fichasApr     Ficha[]              @relation(\"Aprendices\")\n  materias      Materia[]            @relation(\"InstructorMaterias\")\n  asistencias   Asistencia[]         @relation(\"InstructorAsistencia\")\n  registros     RegistroAsistencia[]\n  excusas       Excusa[]\n  snakeScore    SnakeScore?\n  breakoutScore BreakoutScore?\n  flappyScore   FlappyScore?\n  towerScore    TowerScore?\n  reactionScore ReactionScore?\n  memoryScore   MemoryScore?\n  wordleScore   WordleScore?\n  userSkins     UserSkin[]\n}\n\nmodel Ficha {\n  id        String   @id @default(cuid())\n  numero    String   @unique\n  nivel     String\n  centro    String\n  jornada   String\n  region    String   @default(\"\")\n  duracion  Int      @default(0)\n  code      String   @unique\n  createdAt DateTime @default(now())\n\n  instructorAdminId String\n  instructorAdmin   User   @relation(\"InstructorAdmin\", fields: [instructorAdminId], references: [id])\n\n  instructores FichaInstructor[]\n  aprendices   User[]            @relation(\"Aprendices\")\n\n  materias Materia[]\n  horarios Horario[]\n}\n\nmodel FichaInstructor {\n  id           String @id @default(cuid())\n  role         String @default(\"invitado\") // 'admin' | 'invitado'\n  fichaId      String\n  instructorId String\n  ficha        Ficha  @relation(fields: [fichaId], references: [id], onDelete: Cascade)\n  instructor   User   @relation(fields: [instructorId], references: [id], onDelete: Cascade)\n\n  @@unique([fichaId, instructorId])\n}\n\nmodel Materia {\n  id     String @id @default(cuid())\n  nombre String\n  tipo   String\n\n  fichaId String\n  ficha   Ficha  @relation(fields: [fichaId], references: [id], onDelete: Cascade)\n\n  instructorId String\n  instructor   User   @relation(\"InstructorMaterias\", fields: [instructorId], references: [id])\n\n  asistencias Asistencia[]\n  horarios    Horario[]\n}\n\nmodel Horario {\n  id         String @id @default(cuid())\n  dia        String // 'Lunes', 'Martes', etc.\n  horaInicio String // '08:00'\n  horaFin    String // '10:00'\n\n  fichaId String\n  ficha   Ficha  @relation(fields: [fichaId], references: [id], onDelete: Cascade)\n\n  materiaId String\n  materia   Materia @relation(fields: [materiaId], references: [id], onDelete: Cascade)\n}\n\nmodel Asistencia {\n  id        String   @id @default(cuid())\n  fecha     String\n  activa    Boolean  @default(true)\n  timestamp DateTime @default(now())\n\n  materiaId String\n  materia   Materia @relation(fields: [materiaId], references: [id], onDelete: Cascade)\n\n  instructorId String\n  instructor   User   @relation(\"InstructorAsistencia\", fields: [instructorId], references: [id])\n\n  registros RegistroAsistencia[]\n}\n\nmodel RegistroAsistencia {\n  id        String   @id @default(cuid())\n  presente  Boolean  @default(true)\n  metodo    String   @default(\"manual\") // 'qr', 'codigo', 'manual', 'facial', 'huella', 'nfc'\n  timestamp DateTime @default(now())\n\n  asistenciaId String\n  asistencia   Asistencia @relation(fields: [asistenciaId], references: [id], onDelete: Cascade)\n\n  aprendizId String\n  aprendiz   User   @relation(fields: [aprendizId], references: [id], onDelete: Cascade)\n\n  @@unique([asistenciaId, aprendizId])\n}\n\nmodel Excusa {\n  id          String    @id @default(cuid())\n  motivo      String\n  descripcion String\n  fechas      String\n  estado      String    @default(\"Pendiente\")\n  respuesta   String?\n  archivoUrl  String?\n  createdAt   DateTime  @default(now())\n  respondedAt DateTime?\n\n  aprendizId String\n  aprendiz   User   @relation(fields: [aprendizId], references: [id], onDelete: Cascade)\n}\n\n// Leaderboard global del juego Snake\nmodel SnakeScore {\n  id        String   @id @default(cuid())\n  score     Int\n  updatedAt DateTime @default(now()) @updatedAt\n\n  userId String @unique\n  user   User   @relation(fields: [userId], references: [id], onDelete: Cascade)\n}\n\n// Leaderboard global del juego La Bolita (Breakout)\nmodel BreakoutScore {\n  id        String   @id @default(cuid())\n  score     Int\n  updatedAt DateTime @default(now()) @updatedAt\n\n  userId String @unique\n  user   User   @relation(fields: [userId], references: [id], onDelete: Cascade)\n}\n\n// Leaderboard global del juego El Maní (Flappy Bird)\nmodel FlappyScore {\n  id        String   @id @default(cuid())\n  score     Int\n  updatedAt DateTime @default(now()) @updatedAt\n\n  userId String @unique\n  user   User   @relation(fields: [userId], references: [id], onDelete: Cascade)\n}\n\nmodel TowerScore {\n  id        String   @id @default(cuid())\n  score     Int\n  updatedAt DateTime @default(now()) @updatedAt\n  userId    String   @unique\n  user      User     @relation(fields: [userId], references: [id], onDelete: Cascade)\n}\n\nmodel ReactionScore {\n  id        String   @id @default(cuid())\n  score     Int // milisegundos — menor es mejor\n  updatedAt DateTime @default(now()) @updatedAt\n  userId    String   @unique\n  user      User     @relation(fields: [userId], references: [id], onDelete: Cascade)\n}\n\nmodel MemoryScore {\n  id        String   @id @default(cuid())\n  score     Int\n  updatedAt DateTime @default(now()) @updatedAt\n  userId    String   @unique\n  user      User     @relation(fields: [userId], references: [id], onDelete: Cascade)\n}\n\nmodel WordleScore {\n  id        String   @id @default(cuid())\n  score     Int // intentos usados — menor es mejor\n  updatedAt DateTime @default(now()) @updatedAt\n  userId    String   @unique\n  user      User     @relation(fields: [userId], references: [id], onDelete: Cascade)\n}\n\n// Sistema de Skins para Snake\nmodel SnakeSkin {\n  id          String   @id @default(cuid())\n  name        String   @unique\n  description String\n  price       Float // Precio en pesos colombianos (COP)\n  rarity      String // 'common', 'rare', 'epic', 'legendary', 'mythic'\n  headColor   String\n  bodyColor   String\n  pattern     String // 'solid', 'gradient', 'neon', 'metallic', 'rainbow', 'galaxy', 'fire', 'ice'\n  trailEffect String? // 'none', 'sparkles', 'fire', 'ice', 'lightning', 'stars'\n  eyeStyle    String   @default(\"normal\") // 'normal', 'laser', 'cute', 'angry'\n  isDefault   Boolean  @default(false)\n  createdAt   DateTime @default(now())\n\n  userSkins UserSkin[]\n  orders    SkinOrder[]\n}\n\nmodel UserSkin {\n  id         String   @id @default(cuid())\n  userId     String\n  skinId     String\n  equipped   Boolean  @default(false)\n  unlockedAt DateTime @default(now())\n\n  user User      @relation(fields: [userId], references: [id], onDelete: Cascade)\n  skin SnakeSkin @relation(fields: [skinId], references: [id], onDelete: Cascade)\n\n  @@unique([userId, skinId])\n}\n\nmodel SkinOrder {\n  id            String    @id @default(cuid())\n  userId        String\n  skinId        String\n  amount        Float // Monto pagado\n  currency      String    @default(\"COP\")\n  status        String // 'pending', 'approved', 'rejected', 'cancelled'\n  paymentMethod String? // 'mercadopago', 'epayco', etc.\n  externalId    String? // ID de la transacción en la pasarela\n  preferenceId  String? // ID de preferencia de Mercado Pago\n  createdAt     DateTime  @default(now())\n  approvedAt    DateTime?\n\n  skin SnakeSkin @relation(fields: [skinId], references: [id])\n\n  @@index([userId])\n  @@index([externalId])\n}\n",
